// hooks/useprotocols.js
import { useEffect, useState } from "react";
import { getProtocols } from "../api/protocolsapi";

const MOCK_PROTOCOLS = ["MQTT", "MODBUS", "OPC-UA", "Modbus TCP"];

export const useProtocols = () => {
  const [protocols, setProtocols] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    let mounted = true;

    (async () => {
      try {
        const data = await getProtocols(); // ✅ await the helper
        // Normalize response shape: it might be an array or an object with .protocols
        const list = Array.isArray(data) ? data : data?.protocols;

        if (mounted) {
          if (Array.isArray(list) && list.length) {
            setProtocols(list);
            setError(null);
          } else {
            // Fallback to mock if API returns unexpected structure
            setProtocols(MOCK_PROTOCOLS);
            setError("Unexpected API response. Using defaults.");
          }
        }
      } catch (err) {
        if (mounted) {
          console.log("API unavailable, using mock:", err?.message);
          setProtocols(MOCK_PROTOCOLS);
          setError("Live API not reachable. Showing mock protocols.");
        }
      } finally {
        if (mounted) setLoading(false);
      }
    })();

    return () => {
      mounted = false;
    };
  }, []);

  return { protocols, loading, error };
};
